using HaCreator.MapEditor.Instance;using MapleLib.WzLib.WzStructure.Data.QuestStructure;using System;using System.Windows;
namespace HaCreator.GUI.InstanceEditor{public partial class ObjQuestInput:EditorBase{public ObjectInstanceQuest result;public ObjQuestInput(){InitializeComponent();foreach(QuestStateType state in Enum.GetValues(typeof(QuestStateType)))stateInput.Items.Add(state.ToString());stateInput.SelectedIndex=0;}protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){result=new ObjectInstanceQuest(InstanceEditorDialogSupport.GetInt(idInput),(QuestStateType)stateInput.SelectedIndex);DialogResult=true;}private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventArgs.Empty);}}
